import { useContext, useEffect, useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Trash2, ArchiveRestore, AlertTriangle, FileText } from "lucide-react";
import { LangContext } from "@/lib/i18n";
import { useToast } from "@/hooks/use-toast";

interface TrashItem {
  id: number;
  name: string;
  fileName: string;
  rowCount: number;
  createdAt: number;
  deletedAt: number;
}

export default function TrashPage() {
  const { lang } = useContext(LangContext);
  const isAr = lang === "ar";
  const qc = useQueryClient();
  const { toast } = useToast();

  const L = {
    title: isAr ? "سلّة المحذوفات" : "Trash",
    empty: isAr ? "السلّة فارغة" : "Trash is empty",
    restore: isAr ? "استعادة" : "Restore",
    purge: isAr ? "حذف نهائي" : "Delete permanently",
    rows: isAr ? "صف" : "rows",
    deletedAt: isAr ? "حُذف في" : "Deleted at",
    confirmPurge: isAr ? "حذف نهائي ولا يمكن التراجع. متأكد؟" : "Permanent delete. Are you sure?",
    restored: isAr ? "تم الاستعادة ✓" : "Restored ✓",
    purged: isAr ? "تم الحذف نهائياً" : "Permanently deleted",
  };

  const { data, isLoading } = useQuery<{ items: TrashItem[] }>({
    queryKey: ["trash"],
    queryFn: async () => {
      const res = await apiRequest("GET", "/api/datasets/trash/list");
      return res.json();
    },
  });

  const restoreMut = useMutation({
    mutationFn: async (id: number) => {
      await apiRequest("POST", `/api/datasets/${id}/restore`);
    },
    onSuccess: () => {
      toast({ description: L.restored, duration: 1800 });
      qc.invalidateQueries({ queryKey: ["trash"] });
      qc.invalidateQueries({ queryKey: ["/api/datasets"] });
      qc.invalidateQueries({ queryKey: ["/api/dashboard/stats"] });
    },
  });

  const purgeMut = useMutation({
    mutationFn: async (id: number) => {
      await apiRequest("DELETE", `/api/datasets/${id}/purge`);
    },
    onSuccess: () => {
      toast({ description: L.purged, duration: 1800 });
      qc.invalidateQueries({ queryKey: ["trash"] });
    },
  });

  const items = data?.items || [];

  return (
    <div className="container mx-auto p-4 space-y-4">
      <div className="flex items-center gap-2">
        <Trash2 className="w-5 h-5 text-muted-foreground" />
        <h1 className="text-xl font-bold">{L.title}</h1>
        <span className="text-xs text-muted-foreground">({items.length})</span>
      </div>

      {isLoading ? (
        <div className="text-sm text-muted-foreground">...</div>
      ) : items.length === 0 ? (
        <Card>
          <CardContent className="p-8 text-center text-sm text-muted-foreground">
            <Trash2 className="w-10 h-10 mx-auto mb-2 opacity-40" />
            {L.empty}
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-2">
          {items.map((it) => (
            <Card key={it.id} className="overflow-hidden">
              <CardContent className="p-3 flex items-center gap-3">
                <FileText className="w-5 h-5 text-muted-foreground shrink-0" />
                <div className="flex-1 min-w-0">
                  <div className="font-semibold text-sm truncate">{it.name}</div>
                  <div className="text-xs text-muted-foreground flex flex-wrap gap-2">
                    <span>{it.rowCount.toLocaleString()} {L.rows}</span>
                    <span>·</span>
                    <span>
                      {L.deletedAt}: {new Date(it.deletedAt).toLocaleString(isAr ? "ar-SA" : "en-US")}
                    </span>
                  </div>
                </div>
                <div className="flex gap-1">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => restoreMut.mutate(it.id)}
                    disabled={restoreMut.isPending}
                    className="h-8 text-xs gap-1"
                  >
                    <ArchiveRestore className="w-3.5 h-3.5" />
                    {L.restore}
                  </Button>
                  <Button
                    variant="destructive"
                    size="sm"
                    onClick={() => {
                      if (confirm(L.confirmPurge)) purgeMut.mutate(it.id);
                    }}
                    disabled={purgeMut.isPending}
                    className="h-8 text-xs gap-1"
                  >
                    <AlertTriangle className="w-3.5 h-3.5" />
                    {L.purge}
                  </Button>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}
